SELECT * FROM ( SELECT innerQ.*, ROWNUM rn FROM ( SELECT p.PLACE_ID , p.PLACE_TYPE , p.NAME , p.ADDRESS , p.VIEW_COUNT , p.IMAGE_URL , p.CREATED_AT AS CREATED_AT FROM PLACE p WHERE (p.NAME LIKE '%'||#{keyword}||'%' OR p.ADDRESS LIKE '%'||#{keyword}||'%')
AND p.PLACE_TYPE = #{type}
ORDER BY p.CREATED_AT DESC
ORDER BY p.VIEW_COUNT DESC
) innerQ WHERE ROWNUM <= #{endRow} ) WHERE rn > #{startRow}

SELECT p.PLACE_ID AS PLACE_ID , COUNT(rv.REVIEW_ID) AS REVIEW_COUNT , NVL(ROUND(AVG(rv.RATING), 1), 0) AS AVG_RATING FROM PLACE p LEFT JOIN REVIEW rv ON p.PLACE_ID = rv.PLACE_ID AND rv.STATUS = 'DISPLAY' WHERE (p.NAME LIKE '%' || #{keyword} || '%' OR p.ADDRESS LIKE '%' || #{keyword} || '%')
AND p.PLACE_TYPE = #{type}
GROUP BY p.PLACE_ID

